170→    }, []);
171→
172→
173→    const applyTextFormat = (format) => {
174→        editor.dispatchCommand(FORMAT_TEXT_COMMAND, format)
175→    }
176→
177→    const applyTextStyle = useCallback((styles) => {
178→        const sanitizedStyles = Object.fromEntries(
179→            Object.entries(styles).map(([key, value]) => [key, value ?? ''])
180→        );
181→        editor.update(() => {
182→            const selection = $getSelection();
183→            if ($isRangeSelection(selection)) {
