    border-radius: 15px;
    background-color: var(--bg-pill);
    color: var(--text-muted);
    font-weight: 650;
    user-select: none;
    border: none;
    cursor: not-allowed;
}
.editor-save-bttn-disabled:focus {
    outline: none;
}

.composer-mode-btn{
