}
.southwest-side-handle {
    position: absolute;
    bottom: -4px;
    left: -4px;
    width: 12px;
    height: 12px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 50%;
    cursor: nesw-resize;
    z-index: 10;
}
.northeast-side-handle {
    position: absolute;
    top: -4px;
    right: -4px;
    width: 12px;
    height: 12px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 50%;
    cursor: sw-resize;
    z-index: 10;
}
.northwest-side-handle {
    position: absolute;
    top: -4px;
    left: -4px;
    width: 12px;
    height: 12px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 50%;
    cursor: se-resize;
    z-index: 10;
}
.east-side-handle {
    position: absolute;
    top: 50%;
    right: -4px;
    width: 8px;
    height: 20px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 2px;
    transform: translateY(-50%);
    cursor: ew-resize;
    z-index: 10;
}
.south-side-handle {
    position: absolute;
    bottom: -4px;
    left: 50%;
    width: 20px;
    height: 8px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 2px;
    transform: translateX(-50%);
    cursor: ns-resize;
    z-index: 10;
}
.north-side-handle {
    position: absolute;
    top: -4px;
    left: 50%;
    width: 20px;
    height: 8px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 2px;
    transform: translateX(-50%);
    cursor: nw-resize;
    z-index: 10;
}

/* ── Image loading overlay ── */
.image-loading-overlay {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    background-color: rgba(0, 0, 0, 0.45);
    border-radius: 5px;
    gap: 8px;
    pointer-events: none;
}
.image-loading-spinner {
    width: 28px;
    height: 28px;
