        throw {status: 500, error: 'error uploading journal images'}
    }
}

export const uploadJournalContentController = async(req, res) =>{
    const {
        content,
        title,
        post_type: postType,
        canvas_doc: canvasDoc,
        remix_source_journal_id: remixSourceJournalId,
        is_remix: isRemix,
        prompt_id: promptId
    } = req.body;
    const userId = req.userId;
    try {
        const result = await uploadJournalContentService(content, title, userId, postType, canvasDoc, remixSourceJournalId, isRemix, promptId);
