                let heading = null;
                let quote = false;
                let alignment = 'left';

                if (element) {
                    if ($isHeadingNode(element)) {
                        heading = element.getTag(); // 'h1', 'h2', 'h3'
                    }
                    if ($isQuoteNode(element)) {
                        quote = true;
                    }
                    const formatType = element.getFormatType?.();
