 405→const evaluateShareImageCandidate = (rawUrl) => {
 406→    const absoluteUrl = resolveAbsoluteHttpUrl(rawUrl);
 407→    if (!absoluteUrl) {
 408→        return {
 409→            ok: false,
 410→            reason: 'invalid_or_non_http_url',
 411→            resolvedUrl: null,
 412→        };
 413→    }
 414→
 415→    let path = '';
 416→    try {
 417→        const parsed = new URL(absoluteUrl);
 418→        path = String(parsed.pathname || '').toLowerCase();
 419→    } catch {
 420→        return {
 421→            ok: false,
 422→            reason: 'invalid_resolved_url',
 423→            resolvedUrl: null,
 424→        };
 425→    }
 426→
 427→    if (path.endsWith('.svg')) {
 428→        return {
 429→            ok: false,
 430→            reason: 'svg_not_supported_for_share_image',
 431→            resolvedUrl: absoluteUrl,
 432→        };
 433→    }
 434→
 435→    if (!isSafeRemoteImageUrl(absoluteUrl)) {
 436→        return {
 437→            ok: false,
 438→            reason: 'unsafe_remote_url',
 439→            resolvedUrl: absoluteUrl,
 440→        };
 441→    }
 442→
 443→    return {
 444→        ok: true,
 445→        reason: 'ok',
 446→        resolvedUrl: absoluteUrl,
 447→    };
 448→};
