 561→app.use((req, res, next) => {
 562→    metricsState.requests += 1;
 563→    metricsState.inFlight += 1;
 564→
 565→    const startNs = process.hrtime.bigint();
 566→    let byteCount = 0;
 567→
 568→    const originalWrite = res.write.bind(res);
 569→    const originalEnd = res.end.bind(res);
 570→
 571→    res.write = (chunk, encoding, callback) => {
 572→        if (chunk) {
 573→            byteCount += Buffer.isBuffer(chunk)
 574→                ? chunk.length
 575→                : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
 576→        }
 577→        return originalWrite(chunk, encoding, callback);
 578→    };
 579→
 580→    res.end = (chunk, encoding, callback) => {
 581→        if (chunk) {
 582→            byteCount += Buffer.isBuffer(chunk)
 583→                ? chunk.length
 584→                : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
 585→        }
 586→        return originalEnd(chunk, encoding, callback);
 587→    };
 588→
 589→    res.on('finish', () => {
 590→        metricsState.inFlight = Math.max(0, metricsState.inFlight - 1);
 591→        metricsState.responses += 1;
 592→        metricsState.bytesSent += byteCount;
 593→
 594→        const statusBucket = classifyStatusBucket(res.statusCode);
 595→        metricsState.statusBuckets[statusBucket] += 1;
 596→
 597→        const durationMs = Number(process.hrtime.bigint() - startNs) / 1_000_000;
 598→        const routeTemplate = req.route?.path
 599→            ? `${req.baseUrl || ''}${req.route.path}`
 600→            : req.path;
 601→        const routeKey = `${req.method} ${canonicalizeMetricsPath(routeTemplate)}`;
 602→
 603→        let routeStat = metricsState.routeStats.get(routeKey);
 604→        if (!routeStat) {
 605→            if (metricsState.routeStats.size >= METRICS_ROUTE_LIMIT) {
 606→                return;
 607→            }
 608→
 609→            routeStat = {
 610→                count: 0,
 611→                totalDurationMs: 0,
 612→                maxDurationMs: 0,
 613→                bytesSent: 0,
 614→                statusBuckets: { '2xx': 0, '3xx': 0, '4xx': 0, '5xx': 0, other: 0 },
 615→            };
 616→            metricsState.routeStats.set(routeKey, routeStat);
 617→        }
 618→
 619→        routeStat.count += 1;
 620→        routeStat.totalDurationMs += durationMs;
 621→        routeStat.maxDurationMs = Math.max(routeStat.maxDurationMs, durationMs);
 622→        routeStat.bytesSent += byteCount;
 623→        routeStat.statusBuckets[statusBucket] += 1;
 624→    });
 625→
 626→    next();
 627→});
 628→
 629→app.use((req, res, next) => {
 630→    if (req.method !== "GET") {
 631→        return next();
 632→    }
 633→
 634→    const normalizedPath = normalizeApiPath(req.path);
 635→    const isPersonalized = isPersonalizedGetRequest(req);
 636→
 637→    if (!isPersonalized && isCacheablePublicPath(normalizedPath)) {
