    }
    cluster.on('exit', (worker, code, signal) => {
        console.warn(`Worker ${worker.process.pid} exited (code=${code}, signal=${signal}). Restarting...`);
        cluster.fork();
    });
    // Primary does nothing else — workers handle all requests
} else {
