}
.user-info-email-container{
    display: none;
}
.user-info-email{
    padding: 0;
    margin: 0;
    font-family: var(--font-ui);
    font-size: 0.75rem;
    font-weight: 400;
    color: var(--text-faint);
}
.user-post-date-container{
    display: flex;
    justify-content: center;
    align-items: center;
    width: fit-content;
    height: fit-content;
    cursor: default;
    user-select: none;
}
.user-post-privacy{
    display: flex;
    justify-content: center;
    align-items: center;
    width: fit-content;
    height: fit-content;
