    }
    .search-gallery-hint{
        margin: 0 0.5rem 0.42rem 0.5rem;
        font-size: 0.6rem;
        padding: 0.3rem 0.5rem;
        border-radius: 6px;
    }
    .search-suggestions-dropdown{
        left: 0.5rem;
        right: 0.5rem;
        top: calc(100% - 0.1rem);
        max-height: 260px;
        border-radius: 8px;
    }
    .search-suggestion-item{
        padding: 0.52rem 0.7rem;
        border-left-width: 2px;
    }
    .search-suggestion-title{
        font-size: 0.76rem;
    }
    .search-suggestion-meta{
        font-size: 0.62rem;
    }

    /* ── Inline Write button (mobile only) ── */
    .mobile-write-btn{
        display: flex;
        align-items: center;
        gap: 0.3rem;
        border: 1.5px solid rgba(212, 168, 83, 0.4);
        background: linear-gradient(135deg, rgba(212, 168, 83, 0.15), rgba(212, 168, 83, 0.08));
        color: #D4A853;
        border-radius: 8px;
        font-family: var(--font-ui);
        font-size: 0.68rem;
        font-weight: 700;
        letter-spacing: 0.01rem;
        padding: 0.38rem 0.6rem;
        cursor: pointer;
        white-space: nowrap;
        -webkit-tap-highlight-color: transparent;
        transition: background 0.15s ease, transform 0.15s ease;
    }
    .mobile-write-btn:active{
        transform: scale(0.96);
    }
    .mobile-write-btn svg{
        flex-shrink: 0;
    }


    .postcards-parent-container {
        position: relative;
        top: 0;
        display: flex;
        flex-direction: column;
        align-items: center;
        width: 100%;
        margin-top: 0.5rem;
        margin-bottom: 1rem;
        gap: 12px;
        padding: 0 10px;
        box-sizing: border-box;
    }
    .postcards-parent-loading-container {
        position: relative;
        top: 60px;
        display: flex;
        justify-content: center;
        align-items: center;
        flex-direction: column;
        width: 100%;
        height: 100vh;
    }
    .cards{
        border-radius: 10px;
        overflow: visible;
        max-width: 100%;
        box-sizing: border-box;
    }
    .card-image-banner{
        max-height: 220px;
        border-radius: 10px 10px 0 0;
    }
    .card-content{
        width: 100%;
        padding: 0.75rem 0.75rem 0.4rem 0.75rem;
