                                        initial={{opacity:0 ,scale:0}}
                                        animate={{opacity:1, scale:1, transition: {type: "tween", duration: 0.1}}}
                                        exit={{opacity:0, scale:0, transition: {type: "tween", duration: 0.1}}}
                                        >
                                            <div className="confirmation-delete-heading">
